import React, { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { supabase } from '../../lib/supabaseClient'

export const BrowseSessions: React.FC = () => {
  const [sessions, setSessions] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [user, setUser] = useState<any>(null)
  const [participants, setParticipants] = useState<Record<string, number>>({})
  const [joinedSessions, setJoinedSessions] = useState<Set<string>>(new Set())
  const [joiningId, setJoiningId] = useState<string | null>(null)

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    setLoading(true)

    // Get current user
    const { data: { user: currentUser } } = await supabase.auth.getUser()
    setUser(currentUser)

    // Get all sessions
    const today = new Date().toISOString().split('T')[0]
    const { data: sessionsData } = await supabase
      .from('sports_sessions')
      .select('*')
      .gte('session_date', today)
      .order('session_date', { ascending: true })

    setSessions(sessionsData || [])

    // Get participant counts for all sessions
    if (sessionsData && sessionsData.length > 0) {
      const counts: Record<string, number> = {}
      const joined: Set<string> = new Set()

      for (const session of sessionsData) {
        // Get participant count
        const { count } = await supabase
          .from('session_participants')
          .select('*', { count: 'exact', head: true })
          .eq('session_id', session.id)
        counts[session.id] = count || 0

        // Check if user has joined
        if (currentUser) {
          const { data: joinedData } = await supabase
            .from('session_participants')
            .select('*')
            .eq('session_id', session.id)
            .eq('user_id', currentUser.id)
          if (joinedData && joinedData.length > 0) {
            joined.add(session.id)
          }
        }
      }

      setParticipants(counts)
      setJoinedSessions(joined)
    }

    setLoading(false)
  }

  const handleJoin = async (sessionId: string) => {
    if (!user) {
      alert('⚠️ Please login first')
      return
    }

    setJoiningId(sessionId)

    const session = sessions.find(s => s.id === sessionId)
    if (!session) {
      setJoiningId(null)
      return
    }

    // Check if already joined
    if (joinedSessions.has(sessionId)) {
      alert('✅ You already joined this session')
      setJoiningId(null)
      return
    }

    // Check if user is the creator
    if (session.created_by === user.id) {
      alert('👑 You cannot join your own session')
      setJoiningId(null)
      return
    }

    // Check if full
    const currentCount = participants[sessionId] || 0
    if (currentCount >= session.max_participants) {
      alert('🔴 This session is full!')
      setJoiningId(null)
      return
    }

    // Join session
    const { error } = await supabase
      .from('session_participants')
      .insert({
        session_id: sessionId,
        user_id: user.id
      })

    if (error) {
      alert('❌ Failed to join: ' + error.message)
    } else {
      alert('✅ You have joined the session!')
      // Reload data
      await loadData()
    }
    setJoiningId(null)
  }

  if (loading) {
    return (
      <div style={{
        minHeight: '100vh',
        background: '#0a0a0a',
        color: 'white',
        padding: '40px',
        textAlign: 'center'
      }}>
        Loading sessions...
      </div>
    )
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: '#0a0a0a',
      color: 'white',
      padding: '24px'
    }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h1 style={{ color: '#FFD700', fontSize: '28px' }}>📅 Browse Sessions</h1>
            <p style={{ color: '#666' }}>Find and join sports sessions near you</p>
          </div>
          <Link to="/create-session" style={{
            background: '#c8a200',
            color: '#0a0a0a',
            padding: '10px 20px',
            borderRadius: '8px',
            textDecoration: 'none',
            fontWeight: 'bold'
          }}>
            + Create Session
          </Link>
        </div>

        {sessions.length === 0 ? (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '16px',
            padding: '60px',
            textAlign: 'center',
            color: '#666'
          }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>🏟️</div>
            <h2 style={{ color: '#888' }}>No sessions yet</h2>
            <p>Be the first to create a session!</p>
          </div>
        ) : (
          sessions.map((session) => {
            const isCreator = session.created_by === user?.id
            const currentCount = participants[session.id] || 0
            const isFull = currentCount >= session.max_participants
            const hasJoined = joinedSessions.has(session.id)
            const canJoin = !isCreator && !isFull && !hasJoined
            const isJoining = joiningId === session.id

            return (
              <div key={session.id} style={{
                background: '#0d0d0d',
                border: `1px solid ${hasJoined ? '#52c07a40' : ' #c8a20020'}`,
                borderRadius: '12px',
                padding: '20px',
                marginBottom: '12px'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ flex: 1 }}>
                    <h3 style={{ fontSize: '18px', fontWeight: 'bold' }}>{session.sport_type}</h3>
                    <p style={{ color: '#888', fontSize: '14px', marginTop: '4px' }}>
                      📍 {session.location}
                    </p>
                    <p style={{ color: '#666', fontSize: '13px' }}>
                      📅 {session.session_date} at {session.session_time.substring(0, 5)}
                    </p>
                    {session.description && (
                      <p style={{ color: '#666', fontSize: '13px', marginTop: '8px' }}>
                        {session.description}
                      </p>
                    )}
                    <div style={{ display: 'flex', gap: '12px', marginTop: '8px', flexWrap: 'wrap' }}>
                      <span style={{
                        background: '#1a1a1a',
                        padding: '4px 12px',
                        borderRadius: '20px',
                        fontSize: '12px',
                        color: '#888'
                      }}>
                        👥 {currentCount} / {session.max_participants}
                      </span>
                      {isCreator && (
                        <span style={{
                          background: '#c8a20020',
                          padding: '4px 12px',
                          borderRadius: '20px',
                          fontSize: '12px',
                          color: '#c8a200'
                        }}>
                          👑 Your Session
                        </span>
                      )}
                      {isFull && !isCreator && (
                        <span style={{
                          background: '#ff444420',
                          padding: '4px 12px',
                          borderRadius: '20px',
                          fontSize: '12px',
                          color: '#ff4444'
                        }}>
                          🔴 Full
                        </span>
                      )}
                      {hasJoined && (
                        <span style={{
                          background: '#52c07a20',
                          padding: '4px 12px',
                          borderRadius: '20px',
                          fontSize: '12px',
                          color: '#52c07a'
                        }}>
                          ✅ Joined
                        </span>
                      )}
                      {session.whatsapp_link && (
                        <a href={session.whatsapp_link} target="_blank" rel="noopener noreferrer" style={{
                          background: '#25D36620',
                          padding: '4px 12px',
                          borderRadius: '20px',
                          fontSize: '12px',
                          color: '#25D366',
                          textDecoration: 'none'
                        }}>
                          💬 WhatsApp Group
                        </a>
                      )}
                    </div>
                  </div>
                  <div style={{ marginLeft: '16px' }}>
                    {canJoin ? (
                      <button
                        onClick={() => handleJoin(session.id)}
                        disabled={isJoining}
                        style={{
                          padding: '8px 20px',
                          background: isJoining ? '#666' : '#c8a200',
                          color: isJoining ? '#444' : '#0a0a0a',
                          border: 'none',
                          borderRadius: '8px',
                          fontWeight: 'bold',
                          cursor: isJoining ? 'default' : 'pointer',
                          fontSize: '14px',
                          minWidth: '80px'
                        }}
                      >
                        {isJoining ? '⏳' : 'Join'}
                      </button>
                    ) : isCreator ? (
                      <button
                        disabled
                        style={{
                          padding: '8px 20px',
                          background: '#1a1a1a',
                          color: '#444',
                          border: 'none',
                          borderRadius: '8px',
                          fontSize: '14px',
                          cursor: 'not-allowed',
                          minWidth: '80px'
                        }}
                      >
                        👑
                      </button>
                    ) : isFull ? (
                      <button
                        disabled
                        style={{
                          padding: '8px 20px',
                          background: '#1a1a1a',
                          color: '#ff444488',
                          border: 'none',
                          borderRadius: '8px',
                          fontSize: '14px',
                          cursor: 'not-allowed',
                          minWidth: '80px'
                        }}
                      >
                        Full
                      </button>
                    ) : hasJoined ? (
                      <button
                        disabled
                        style={{
                          padding: '8px 20px',
                          background: '#1a3a1a',
                          color: '#52c07a',
                          border: 'none',
                          borderRadius: '8px',
                          fontSize: '14px',
                          cursor: 'default',
                          minWidth: '80px'
                        }}
                      >
                        ✅
                      </button>
                    ) : null}
                  </div>
                </div>
              </div>
            )
          })
        )}
      </div>
    </div>
  )
}
